INSERT INTO public.system_config (key, value, description, updated_at) VALUES ('composer.silent_anchor_v195', 'true'::jsonb, 'v195 per-speaker silent-face freeze tiles in the dialog stitch mux. Uses master plate frame 0 at preclip_crop bbox; active Sync.so overlays cover during voiced windows.', NOW()) ON CONFLICT (key) DO UPDATE SET value = EXCLUDED.value, description = EXCLUDED.description, updated_at = NOW(); INSERT INTO public.system_config (key, value, description, updated_at) VALUES ('composer.silent_faces_v183', 'false'::jsonb, 'v183/v190 portrait-based ghost overlays (disabled in v192; superseded by v195).', NOW()) ON CONFLICT (key) DO UPDATE SET value = 'false'::jsonb, updated_at = NOW();